/// For a given pointer argument, this class stores a list of constant ranges
/// that are accessed by the function.
class ArgumentAccessInfo {
public:
  enum AccessType {
    /// The argument is not accessed.
    NoAccess,
    /// The argument is read from.
    Read,
    /// The argument is written to.
    Write,
    /// The argument is written to, and has other side effects, e.g. captured.
    WriteWithSideEffect,
    /// The access type is unknown.
    Unknown
  };

private:
  AccessType Type;

  /// A list of ranges that are accessed. The ranges are specified in bytes from
  /// the pointer argument.
  ConstantRangeList Ranges;

public:
  ArgumentAccessInfo(AccessType Type, ConstantRangeList &&Ranges)
      : Type(Type), Ranges(std::move(Ranges)) {}

  bool hasAccess() const { return Type != NoAccess; }
  bool isReadOnly() const { return Type == Read; }
  bool isWriteOnly() const { return Type == Write; }
  bool isReadOrWrite() const { return isReadOnly() || isWriteOnly(); }
  bool isUnknown() const { return Type == Unknown; }

  /// Union the access info with another.
  void unionWith(ArgumentAccessInfo &&Other) {
    if (Other.isUnknown() || isUnknown()) {
      Type = Unknown;
      Ranges.clear();
      return;
    }
    if (!Other.hasAccess())
      return;
    if (!hasAccess()) {
      Type = Other.Type;
      Ranges = std::move(Other.Ranges);
      return;
    }

    if (isReadOnly() && Other.isReadOnly())
      Type = Read;
    else if (isWriteOnly() && Other.isWriteOnly())
      Type = Write;
    else
      Type = WriteWithSideEffect;

    for (const ConstantRange &CR : Other.Ranges)
      Ranges.insert(CR);
  }

  const ConstantRangeList &getRanges() const { return Ranges; }
};

struct ArgumentUse {
  /// The use of the argument.
  Use *U;
  /// The offset from the argument.
  std::optional<int64_t> Offset;
};

struct ArgumentUses {
  /// A list of uses of the argument.
  SmallVector<ArgumentUse, 8> Uses;
  /// True if the argument is written to.
  bool HasAnyWrite = false;
};

/// Return true if the given instruction is a potential use of the argument.
static bool isUseInstruction(Instruction *I) {
  return isa<LoadInst, StoreInst, MemIntrinsic, CallBase>(I);
}

/// Given an argument, returns a list of instructions that use it.
static ArgumentUses getArgumentUses(Argument &Arg) {
  ArgumentUses Result;
  SmallVector<ArgumentUse, 32> Worklist;

  for (Use &U : Arg.uses())
    Worklist.push_back({&U, 0});

  // We need to keep track of visited GEPs to avoid infinite loops.
  SmallPtrSet<Value *, 32> VisitedGEPs;

  while (!Worklist.empty()) {
    ArgumentUse ArgUse = Worklist.pop_back_val();
    User *U = ArgUse.U->getUser();

    if (auto *I = dyn_cast<Instruction>(U))
      if (isUseInstruction(I)) {
        Result.Uses.push_back(ArgUse);
        continue;
      }

    if (auto *GEP = dyn_cast<GEPOperator>(U)) {
      if (VisitedGEPs.insert(GEP).second) {
        std::optional<int64_t> NewOffset = std::nullopt;
        const DataLayout &DL = GEP->getModule()->getDataLayout();
        unsigned PointerSize = DL.getPointerSizeInBits(GEP->getPointerAddressSpace());
        if (ArgUse.Offset) {
          APInt Offset(PointerSize, 0);
          if (GEP->accumulateConstantOffset(DL, Offset))
            NewOffset = *ArgUse.Offset + Offset.getSExtValue();
        }
        for (Use &UU : GEP->uses())
          Worklist.push_back({&UU, NewOffset});
      }
      continue;
    }

    if (isa<BitCastInst, AddrSpaceCastInst>(U)) {
      for (Use &UU : U->uses())
        Worklist.push_back({&UU, ArgUse.Offset});
      continue;
    }
  }
  return Result;
}

